export const getAllProducts = () => Object.values(productsByCategory).flat();

export const getProductsByCategory = (categoryIdOrSlug) => {
  if (!categoryIdOrSlug || categoryIdOrSlug === "all") return getAllProducts();
  if (categoryIdOrSlug === "Handmade-Accessories") {
    return [
      ...(productsByCategory["Handmade-Accessories"] || []),
      ...(productsByCategory["Oxidised-jewellery"] || [])];
  }
  if (categoryIdOrSlug === "Oxidised-jewellery" || categoryIdOrSlug === "oxidised-jewellery") {
    return [
      ...(productsByCategory["Handmade-Accessories"] || []),
      ...(productsByCategory["Oxidised-jewellery"] || [])];
  }
  const category = categories.find(cat => cat.id === categoryIdOrSlug || cat.slug === categoryIdOrSlug);
  if (!category) return [];
  const primary = productsByCategory[category.id] || [];
  // Also include products from other categories that list this as a secondary category
  const secondary = getAllProducts().filter(p =>
    p.categoryId !== category.id &&
    p.meta?.secondaryCategories?.includes(category.id)
  );
  return [...primary, ...secondary];
};

export const getProductById = (id) => getAllProducts().find(product => product.id === parseInt(id));
export const getProductBySlug = (slug) => getAllProducts().find(product => product.slug === slug);
export const getCategoryByIdOrSlug = (idOrSlug) => categories.find(cat => cat.id === idOrSlug || cat.slug === idOrSlug);
export const getFeaturedProducts = () => getAllProducts().filter(product => product.featured);
export const getPopularProducts = () => getAllProducts().filter(product => product.popular);
export const getFeaturedCategories = () => categories.filter(cat => cat.featured).sort((a, b) => a.order - b.order);
export const getSortedCategories = () => [...categories].sort((a, b) => a.order - b.order);
export const getCategoryProductCount = (categoryId) => {
  if (categoryId === "Handmade-Accessories") {
    return (productsByCategory["Handmade-Accessories"] || []).length + (productsByCategory["Oxidised-jewellery"] || []).length;
  }
  return (productsByCategory[categoryId] || []).length;
};

export const products = getAllProducts().map(product => {
  const category = getCategoryByIdOrSlug(product.categoryId);
  return { ...product, category: category?.name || product.categoryId };
});

export const categoriesLegacy = categories.map(cat => ({ id: cat.id, name: cat.name, icon: cat.icon, count: getCategoryProductCount(cat.id) }));

export const getProductsByCategoryName = (categoryName) => {
  if (!categoryName || categoryName === "All") return getAllProducts();
  const category = categories.find(cat => cat.name === categoryName);
  if (!category) return [];
  return getProductsByCategory(category.id);
};

export const getPopularItems = getPopularProducts;
export const getItemsByCategory = getProductsByCategoryName;